/**
 * Cleanup Envelope Corruption — SessionStart Hook (#1826)
 *
 * Backfill mitigation for the `{"continue":true,"suppressOutput":true}`
 * envelope leak (originally #1250, recurring as #1826). Sweeps any
 * directories or files whose path segments contain the JSON envelope
 * literal into a quarantine bucket so they stop confusing tooling
 * (ruff, vitest, EnterWorktree, etc.).
 *
 * Scope (conservative — do not roam):
 *   1. ~/.claude/hooks/sessions/*{"continue":*  — historical session-summary corruption
 *   2. <projectDir>/.worktrees/*{"continue":*  — worktree directories named with the envelope
 *
 * Idempotent: writes a marker `~/.claude/.orchestkit-envelope-cleanup-done`
 * after the first successful sweep on a given machine, then short-circuits
 * future runs.
 *
 * Note: the leak SOURCE is in the CC harness (some path reads hook stdout
 * as an identifier instead of parsing it as the hook-protocol response).
 * Yonatan-HQ/platform#3230 tracks the upstream fix. This hook is purely
 * defensive cleanup — it does NOT prevent new leaks. Pair with the
 * safeIdentifier() guard in lib/safe-fs.ts to fail-closed on new ones.
 *
 * Hook event: SessionStart (async, timeout: 5s)
 */

import type { HookInput, HookResult, HookContext } from '../types.js';
import { outputSilentSuccess } from '../lib/common.js';
import { NOOP_CTX } from '../lib/context.js';
import { existsSync, readdirSync, renameSync, writeFileSync } from 'node:fs';
import { join } from 'node:path';
import { getHomeDir, getProjectDir } from '../lib/paths.js';
import { safeMkdirSync } from '../lib/safe-fs.js';

const HOOK_NAME = 'lifecycle/cleanup-envelope-corruption';

const ENVELOPE_MARKERS = ['{"continue":', '"suppressOutput":'];
const DONE_MARKER_FILENAME = '.orchestkit-envelope-cleanup-done';

function isCorrupt(name: string): boolean {
  return ENVELOPE_MARKERS.some(m => name.includes(m));
}

function quarantineDir(): string {
  return join(getHomeDir(), '.claude', 'quarantine', 'envelope-corruption');
}

/**
 * Sweep one parent directory: any child whose name contains the envelope
 * marker gets renamed into the quarantine bucket. Returns the count moved.
 * Silently ignores missing parents and per-entry rename errors — this hook
 * must never block CC.
 */
function sweepParent(parent: string, ctx: HookContext): number {
  if (!existsSync(parent)) return 0;
  let entries: string[];
  try {
    entries = readdirSync(parent);
  } catch {
    return 0;
  }
  const corrupt = entries.filter(isCorrupt);
  if (corrupt.length === 0) return 0;

  const qDir = quarantineDir();
  safeMkdirSync(qDir, { recursive: true });
  if (!existsSync(qDir)) return 0; // safeMkdirSync refused — abort sweep

  let moved = 0;
  const stamp = new Date().toISOString().replace(/[:.]/g, '-');
  for (const entry of corrupt) {
    const src = join(parent, entry);
    // Replace separators in entry name so the quarantine filename is flat.
    const safeName = entry.replace(/[/\\]/g, '_').slice(0, 180);
    const dst = join(qDir, `${stamp}__${safeName}`);
    try {
      renameSync(src, dst);
      moved++;
    } catch (err) {
      ctx.log(HOOK_NAME, `rename failed for ${src}: ${(err as Error).message}`);
    }
  }
  if (moved > 0) {
    ctx.log(HOOK_NAME, `quarantined ${moved} envelope-corrupt entries from ${parent}`);
  }
  return moved;
}

export function cleanupEnvelopeCorruption(
  _input: HookInput,
  ctx: HookContext = NOOP_CTX,
): HookResult {
  const home = getHomeDir();
  const projectDir = getProjectDir();
  let totalMoved = 0;

  // Always-on, cheap sweep (#1978): the harness can leak a new envelope-named
  // entry at any time, so these targets are scanned EVERY SessionStart — they
  // are NOT gated by the done-marker. The project ROOT is the case the original
  // mitigation missed (client at private.ai.remoteicu had the entry at top-level,
  // not under .worktrees). Each is a single readdir of a small directory.
  for (const parent of [projectDir, join(projectDir, '.worktrees')]) {
    totalMoved += sweepParent(parent, ctx);
  }

  // One-time historical sweep of ~/.claude/hooks/sessions — this directory can
  // be large (one entry per session), so the done-marker keeps us from
  // re-scanning it every SessionStart. New leaks no longer hide behind this
  // marker because the always-on sweep above covers the live cases.
  const marker = join(home, '.claude', DONE_MARKER_FILENAME);
  if (!existsSync(marker)) {
    totalMoved += sweepParent(join(home, '.claude', 'hooks', 'sessions'), ctx);

    // Write the marker only if we got far enough to scan — silent failure
    // (e.g. read-only home) shouldn't gate the marker, since retrying the
    // historical sweep every session is pointless if we can't write at all.
    try {
      const markerDir = join(home, '.claude');
      if (!existsSync(markerDir)) safeMkdirSync(markerDir, { recursive: true });
      writeFileSync(
        marker,
        JSON.stringify({
          completed_at: new Date().toISOString(),
          moved: totalMoved,
          issue: 'orchestkit#1978',
        }, null, 2),
      );
    } catch (err) {
      ctx.log(HOOK_NAME, `marker write failed: ${(err as Error).message}`);
    }
  }

  if (totalMoved > 0) {
    ctx.log(HOOK_NAME, `envelope cleanup complete: ${totalMoved} entries quarantined under ${quarantineDir()}`);
  }
  return outputSilentSuccess();
}

